const readline = require('readline');

function main() {
    const rl = readline.createInterface({
        input: process.stdin,
        output: process.stdout
    });

    let inputLine = '';

    rl.on('line', (line) => {
        inputLine = line;
        rl.close();
    });

    rl.on('close', () => {
        // Extract string, character, and integer k from the input line
        let [s1, c1, k] = inputLine.split(' ');
        k = parseInt(k);

        let count = 0;
        let position = -1;

        // Iterate through the string to find the k-th occurrence
        for (let i = 0; i < s1.length; ++i) {
            if (s1[i] === c1) {
                count++;
                if (count === k) {
                    position = i;
                    break;
                }
            }
        }

        // Print the result
        console.log(position);
    });
}

